T_POSITION = 'LONG' THEN DIM_INSTRUMENT_CONTRACT.V_CCY_CODE WHEN     DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE = 'XSFWDSFWD' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'SHORT' THEN DIM_INSTRUMENT_CONTRACT.V_CCY2_CODE WHEN DIM_INSTRUMENT_TYPE.V_DERIVATIVE_TYPE_CODE = 'SWAP' OR (DIM_INSTRUMENT_TYPE.V_RISK_FACTOR_TYPE_CODE = 'XS' AND DIM_INSTRUMENT_TYPE.V_DERIVATIVE_TYPE_CODE <> 'SPOT' AND DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE NOT LIKE '%GLD') OR ((DIM_INSTRUMENT_CONTRACT.V_OPTION_TYPE = 'PUT' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'SHORT') OR (COALESCE(DIM_INSTRUMENT_CONTRACT.V_OPTION_TYPE,'NULL')<> 'PUT' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'LONG')) OR DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE = 'IROPTSCFI' THEN CASE WHEN DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE = 'IRSPOTDCB' THEN DIM_INSTRUMENT_CONTRACT.V_CCY_CODE ELSE COALESCE(DIM_INSTRUMENT_CONTRACT.V_CCY2_CODE,DIM_INSTRUMENT_CONTRACT.V_CCY_CODE) END END,CASE WHEN DIM_INSTRUMENT_TYPE.V_DERIVATIVE_TYPE_CODE = 'SWAP' OR (DIM_INSTRUMENT_TYPE.V_RISK_FACTOR_TYPE_CODE = 'XS' AND DIM_INSTRUMENT_TYPE.V_DERIVATIVE_TYPE_CODE <> 'SPOT' AND DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE NOT LIKE '%GLD') OR ((DIM_INSTRUMENT_CONTRACT.V_OPTION_TYPE = 'PUT' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'LONG' ) OR (COALESCE(DIM_INSTRUMENT_CONTRACT.V_OPTION_TYPE,'NULL')<> 'PUT' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'SHORT')) AND DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE <> 'IROPTSCFI' THEN COALESCE(DIM_INSTRUMENT_CONTRACT.V_BENCHMARK_CODE, DIM_INSTR_CONTRACT_UL_LVL1.V_BENCHMARK_CODE, DIM_INSTR_CONTRACT_UL_LVL2.V_BENCHMARK_CODE) END,CASE WHEN (DIM_INSTRUMENT_TYPE.V_DERIVATIVE_TYPE_CODE = 'SWAP' OR DIM_MR_INSTR_TYPE_UL_LVL1.V_DERIVATIVE_TYPE_CODE = 'SWAP' OR DIM_MR_INSTR_TYPE_UL_LVL2.V_DERIVATIVE_TYPE_CODE = 'SWAP') THEN COALESCE(DIM_INSTRUMENT_CONTRACT.V_BENCHMARK2_CODE, DIM_INSTR_CONTRACT_UL_LVL1.V_BENCHMARK2_CODE, DIM_INSTR_CONTRACT_UL_LVL2.V_BENCHMARK2_CODE) WHEN (DIM_INSTRUMENT_TYPE.V_RISK_FACTOR_TYPE_CODE = 'XS' AND DIM_INSTRUMENT_TYPE.V_DERIVATIVE_TYPE_CODE <> 'SPOT' AND DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE NOT LIKE '%GLD') OR ((DIM_INSTRUMENT_CONTRACT.V_OPTION_TYPE = 'PUT' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'SHORT' ) OR (COALESCE(DIM_INSTRUMENT_CONTRACT.V_OPTION_TYPE,'NULL')<> 'PUT' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'LONG')) THEN COALESCE(DIM_INSTRUMENT_CONTRACT.V_BENCHMARK_CODE, DIM_INSTR_CONTRACT_UL_LVL1.V_BENCHMARK_CODE, DIM_INSTR_CONTRACT_UL_LVL2.V_BENCHMARK_CODE) END,CASE WHEN DIM_INSTRUMENT_TYPE.v_instr_type_code IN ('IRSPOTDCB') THEN DIM_INSTRUMENT_CONTRACT.v_ccy_code END,CASE WHEN DIM_INSTRUMENT_TYPE.v_instr_type_code IN ('IRSPOTDCB') THEN DIM_INSTRUMENT_CONTRACT.v_ccy2_code END,(SELECT V_PARAM_VALUE_CODE FROM RUN_EXE_PARAMETERS WHERE V_PARAM_ID = 'RCY' AND N_RUN_SKEY = '870'),COALESCE(DIM_INSTRUMENT_CONTRACT.v_fixing_dates, DIM_INSTR_CONTRACT_UL_LVL1.v_fixing_dates, DIM_INSTR_CONTRACT_UL_LVL2.v_fixing_dates),COALESCE(DIM_INSTRUMENT_CONTRACT.v_fixing_rates, DIM_INSTR_CONTRACT_UL_LVL1.v_fixing_rates, DIM_INSTR_CONTRACT_UL_LVL2.v_fixing_rates),CASE WHEN DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE = 'XSFWDSFWD' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'LONG' THEN DIM_INSTRUMENT_CONTRACT.V_CCY2_CODE WHEN     DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE = 'XSFWDSFWD' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'SHORT' THEN DIM_INSTRUMENT_CONTRACT.V_CCY_CODE WHEN DIM_INSTRUMENT_TYPE.V_DERIVATIVE_TYPE_CODE = 'SWAP' OR (DIM_INSTRUMENT_TYPE.V_RISK_FACTOR_TYPE_CODE = 'XS' AND DIM_INSTRUMENT_TYPE.V_DERIVATIVE_TYPE_CODE <> 'SPOT' AND DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE NOT LIKE '%GLD') OR ((DIM_INSTRUMENT_CONTRACT.V_OPTION_TYPE = 'PUT' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'LONG' ) OR (COALESCE(DIM_INSTRUMENT_CONTRACT.V_OPTION_TYPE,'NULL')<> 'PUT' AND STG_BANK_POSITIONS.V_INSTRUMENT_POSITION = 'SHORT')) AND DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE <> 'IROPTSCFI' THEN CASE WHEN DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE = 'IRSPOTDCB' THEN DIM_INSTRUMENT_CONTRACT.V_CCY_CODE ELSE COALESCE(DIM_INSTRUMENT_CONTRACT.V_CCY_CODE,DIM_INSTRUMENT_CONTRACT.V_CCY2_CODE) END END,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),to_char(FCT_PARTY_FINANCIALS.N_CET1_CAPITAL_RATIO),to_char(FCT_PARTY_FINANCIALS.N_TOTAL_CAPITAL_RATIO),to_char(FSI_INSTR_TYPE_CLASSIFICATION.N_STD_INSTR_TYPE_SKEY),to_char(RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY),to_char(SEC_POOL_MASTER.N_SEC_POOL_SKEY),STG_BANK_POSITIONS.F_PORTFOLIO_LIQUID_FLAG,to_char(STG_BANK_POSITIONS.N_INCURRED_CVA_LOSSES),to_char(STG_BANK_POSITIONS.N_OTHER_VALUATION_ADJ_AMOUNT),to_char(STG_BANK_POSITIONS.N_VALUATION_ADJ_AMOUNT) FROM DIM_INSTRUMENT_CONTRACT INNER JOIN DIM_DATES ON DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN (SELECT DM.V_INSTRUMENT_CODE, DIT.V_INSTR_TYPE_CODE FROM DIM_INSTRUMENT_CONTRACT DM LEFT JOIN DIM_BANK_INSTRUMENT_TYPE DBIT ON DBIT.V_BANK_INSTR_TYPE_CODE =DM.V_INSTR_TYPE_CODE AND DBIT.F_LATEST_RECORD_INDICATOR = 'Y' LEFT JOIN FSI_INSTR_TYPE_CLASSIFICATION FSI ON FSI.N_BANK_INSTR_TYPE_SKEY = DBIT.N_BANK_INSTR_TYPE_SKEY AND FSI.n_RUN_SKEY = '870' LEFT JOIN DIM_INSTRUMENT_TYPE DIT ON DIT.N_INSTR_TYPE_SKEY = FSI.N_STD_INSTR_TYPE_SKEY WHERE DM.F_LATEST_RECORD_INDICATOR = 'Y') TEMP_INSTR ON TEMP_INSTR.v_instrument_code = DIM_INSTRUMENT_CONTRACT.v_instrument_code LEFT OUTER JOIN DIM_INSTRUMENT_TYPE ON DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE = TEMP_INSTR.V_INSTR_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_TYPE.D_RECORD_START_DATE AND DIM_INSTRUMENT_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_IFSB_CONTRACT_TYPE ON DIM_IFSB_CONTRACT_TYPE.V_IFSB_CONTRACT_TYPE_CODE = DIM_INSTRUMENT_CONTRACT.V_IFSB_CONTRACT_TYPE_CODE LEFT OUTER JOIN DIM_INSTRUMENT_CONTRACT DIM_INSTR_CONTRACT_UL_LVL1 ON DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_INSTR_CONTRACT_UL_LVL1.D_RECORD_START_DATE AND DIM_INSTR_CONTRACT_UL_LVL1.D_RECORD_END_DATE AND DIM_INSTRUMENT_CONTRACT.V_UNDERLYING_SEC_CODE = DIM_INSTR_CONTRACT_UL_LVL1.V_INSTRUMENT_CODE LEFT OUTER JOIN DIM_INSTRUMENT_TYPE DIM_MR_INSTR_TYPE_UL_LVL1 ON DIM_INSTR_CONTRACT_UL_LVL1.V_INSTR_TYPE_CODE = DIM_MR_INSTR_TYPE_UL_LVL1.V_INSTR_TYPE_CODE AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_MR_INSTR_TYPE_UL_LVL1.D_RECORD_START_DATE AND DIM_MR_INSTR_TYPE_UL_LVL1.D_RECORD_END_DATE LEFT OUTER JOIN DIM_INSTRUMENT_CONTRACT DIM_INSTR_CONTRACT_UL_LVL2 ON DIM_INSTR_CONTRACT_UL_LVL1.V_UNDERLYING_SEC_CODE = DIM_INSTR_CONTRACT_UL_LVL2.V_INSTRUMENT_CODE AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_INSTR_CONTRACT_UL_LVL2.D_RECORD_START_DATE AND DIM_INSTR_CONTRACT_UL_LVL2.D_RECORD_END_DATE LEFT OUTER JOIN DIM_INSTRUMENT_TYPE DIM_MR_INSTR_TYPE_UL_LVL2 ON DIM_INSTR_CONTRACT_UL_LVL2.V_INSTR_TYPE_CODE = DIM_MR_INSTR_TYPE_UL_LVL2.V_INSTR_TYPE_CODE AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_MR_INSTR_TYPE_UL_LVL2.D_RECORD_START_DATE AND DIM_MR_INSTR_TYPE_UL_LVL2.D_RECORD_END_DATE INNER JOIN DIM_EXPOSURE ON DIM_EXPOSURE.V_EXPOSURE_ID = DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE /*LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = DIM_INSTRUMENT_CONTRACT.N_GAAP_SKEY*/ INNER JOIN ( SELECT FIC_MIS_DATE ,V_INSTRUMENT_CODE ,F_PORTFOLIO_LIQUID_FLAG ,N_VALUATION_ADJ_AMOUNT ,N_INCURRED_CVA_LOSSES ,N_OTHER_VALUATION_ADJ_AMOUNT ,CASE WHEN SUM(( CASE WHEN UPPER(STG_BANK_POSITIONS.V_INSTRUMENT_POSITION) = 'LONG' THEN 1 WHEN UPPER(STG_BANK_POSITIONS.V_INSTRUMENT_POSITION) = 'SHORT' THEN - 1 END ) * STG_BANK_POSITIONS.N_NO_OF_UNITS) >= 0 THEN 'LONG' ELSE 'SHORT' END AS V_INSTRUMENT_POSITION ,ABS(SUM(( CASE WHEN UPPER(COALESCE(STG_BANK_POSITIONS.V_INSTRUMENT_POSITION, 'LONG')) = 'LONG' THEN 1 WHEN UPPER(COALESCE(STG_BANK_POSITIONS.V_INSTRUMENT_POSITION, 'SHORT')) = 'SHORT' THEN - 1 END ) * STG_BANK_POSITIONS.N_PRICE * STG_BANK_POSITIONS.N_NO_OF_UNITS)) AS N_PRE_NOTIONAL_AMT ,MAX(STG_BANK_POSITIONS.V_LEG_REP_CODE) AS V_LEG_REP_CODE ,ABS(SUM(( CASE WHEN UPPER(COALESCE(STG_BANK_POSITIONS.V_INSTRUMENT_POSITION, 'LONG')) = 'LONG' THEN 1 WHEN UPPER(COALESCE(STG_BANK_POSITIONS.V_INSTRUMENT_POSITION, 'SHORT')) = 'SHORT' THEN - 1 END ) * STG_BANK_POSITIONS.N_NO_OF_UNITS)) AS N_NO_OF_UNITS ,MAX(N_PRICE) N_PRICE ,MAX(N_EXP_MTM_VALUE) N_EXP_MTM_VALUE FROM STG_BANK_POSITIONS WHERE STG_BANK_POSITIONS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') GROUP BY FIC_MIS_DATE ,V_INSTRUMENT_CODE ,F_PORTFOLIO_LIQUID_FLAG ,N_VALUATION_ADJ_AMOUNT ,N_INCURRED_CVA_LOSSES ,N_OTHER_VALUATION_ADJ_AMOUNT ) STG_BANK_POSITIONS ON STG_BANK_POSITIONS.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE AND STG_BANK_POSITIONS.V_INSTRUMENT_CODE = DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE LEFT OUTER JOIN DIM_ORG_STRUCTURE DIM_BANK_POSITION ON STG_BANK_POSITIONS.V_LEG_REP_CODE = DIM_BANK_POSITION.V_ENTITY_CODE AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_BANK_POSITION.D_RECORD_START_DATE AND DIM_BANK_POSITION.D_RECORD_END_DATE LEFT OUTER JOIN DIM_STANDARD_UNIT ON DIM_STANDARD_UNIT.V_STD_UNIT_CODE = DIM_INSTRUMENT_CONTRACT.V_INSTR_UNDERLYING_UNIT LEFT OUTER JOIN FCT_MKT_INSTRUMENT_CONTRACT ON DIM_INSTR_CONTRACT_UL_LVL1.N_INSTRUMENT_SKEY = FCT_MKT_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY AND FCT_MKT_INSTRUMENT_CONTRACT.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE LEFT OUTER JOIN FCT_MKT_INSTRUMENT_CONTRACT FCT_MKT_INSTR_CONTRACT ON DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY = FCT_MKT_INSTR_CONTRACT.N_INSTRUMENT_SKEY AND FCT_MKT_INSTR_CONTRACT.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE LEFT OUTER JOIN ( DIM_PARTY LEFT OUTER JOIN DIM_PARTY_TYPE ON DIM_PARTY.V_PARTY_TYPE = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE ) ON DIM_PARTY.V_PARTY_ID = DIM_INSTRUMENT_CONTRACT.V_COUNTERPARTY_ID AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE LEFT OUTER JOIN DIM_MR_COUNTER_PARTY ON DIM_MR_COUNTER_PARTY.V_COUNTER_PARTY_CODE = DIM_INSTRUMENT_CONTRACT.V_ISSUER_TYPE AND TO_DATE(to_date('20260331','YYYYMMDD')) BETWEEN COALESCE(DIM_MR_COUNTER_PARTY.D_RECORD_START_DATE,TO_DATE(to_date('20260331','YYYYMMDD'))) AND  COALESCE(DIM_MR_COUNTER_PARTY.D_RECORD_END_DATE, TO_DATE(to_date('20260331','YYYYMMDD'))) LEFT OUTER JOIN STG_CTD_MAPPING ON STG_CTD_MAPPING.V_UNDERLYING_BOND_CODE = DIM_INSTR_CONTRACT_UL_LVL1.V_INSTRUMENT_CODE AND STG_CTD_MAPPING.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE LEFT OUTER JOIN DIM_ISSUE ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = DIM_ISSUE.V_ISSUE_CODE AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_ISSUE.D_RECORD_START_DATE AND DIM_ISSUE.D_RECORD_END_DATE INNER JOIN ( FCT_ENTITY_INFO LEFT OUTER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY ) ON FCT_ENTITY_INFO.V_ENTITY_CODE = STG_BANK_POSITIONS.V_LEG_REP_CODE AND FCT_ENTITY_INFO.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY LEFT OUTER JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE  LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'MR' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT OUTER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE /* LEFT OUTER JOIN DIM_RUN_IDENTIFIER ON DIM_RUN_IDENTIFIER.V_RUN_IDENTIFIER_CODE = DIM_INSTRUMENT_CONTRACT.V_RUN_IDENTIFIER_CODE LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND RUN_PARAMETERS.N_RUN_SKEY = '870' AND ( DIM_RUN.F_RUN_DEFINITION_MODE = 'U' OR ( DIM_RUN.F_RUN_DEFINITION_MODE = 'R' AND DIM_RUN_IDENTIFIER.V_RUN_IDENTIFIER_CODE = RUN_PARAMETERS.V_RUN_IDENTIFIER_CODE ) ) */ LEFT OUTER JOIN DIM_BANK_INSTRUMENT_TYPE ON DIM_BANK_INSTRUMENT_TYPE.V_BANK_INSTR_TYPE_CODE = DIM_INSTRUMENT_CONTRACT.V_INSTR_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_BANK_INSTRUMENT_TYPE.D_RECORD_START_DATE AND DIM_BANK_INSTRUMENT_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN ( FSI_INSTR_TYPE_CLASSIFICATION LEFT OUTER JOIN DIM_INSTRUMENT_TYPE ON DIM_INSTRUMENT_TYPE.N_INSTR_TYPE_SKEY = FSI_INSTR_TYPE_CLASSIFICATION.N_STD_INSTR_TYPE_SKEY AND TO_DATE(to_date('20260331','YYYYMMDD')) BETWEEN COALESCE(DIM_INSTRUMENT_TYPE.D_RECORD_START_DATE,TO_DATE(to_date('20260331','YYYYMMDD'))) AND  COALESCE(DIM_INSTRUMENT_TYPE.D_RECORD_END_DATE, TO_DATE(to_date('20260331','YYYYMMDD'))) ) ON DIM_BANK_INSTRUMENT_TYPE.N_BANK_INSTR_TYPE_SKEY = FSI_INSTR_TYPE_CLASSIFICATION.N_BANK_INSTR_TYPE_SKEY AND FSI_INSTR_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_INSTR_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' LEFT OUTER JOIN ( FCT_PARTY_FINANCIALS INNER JOIN ( SELECT N_PARTY_SKEY ,MAX(D_PERIOD_END_DATE) D_PERIOD_END_DATE FROM FCT_PARTY_FINANCIALS WHERE V_FINANCIAL_PERIOD_INDICATOR = 'A' AND D_PERIOD_END_DATE <= to_date('20260331','YYYYMMDD') GROUP BY N_PARTY_SKEY ) FCT_PARTY_FINANCIALS_DATE ON FCT_PARTY_FINANCIALS_DATE.N_PARTY_SKEY = FCT_PARTY_FINANCIALS.N_PARTY_SKEY AND FCT_PARTY_FINANCIALS_DATE.D_PERIOD_END_DATE = FCT_PARTY_FINANCIALS.D_PERIOD_END_DATE ) ON FCT_PARTY_FINANCIALS.V_FINANCIAL_PERIOD_INDICATOR = 'A' AND FCT_PARTY_FINANCIALS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY LEFT OUTER JOIN DIM_INDEX ON DIM_INDEX.V_INDEX_CODE = DIM_INSTRUMENT_CONTRACT.V_INDEX_CODE AND TO_DATE(to_date('20260331','YYYYMMDD')) BETWEEN COALESCE(DIM_INDEX.D_RECORD_START_DATE,TO_DATE(to_date('20260331','YYYYMMDD'))) AND COALESCE(DIM_INDEX.D_RECORD_END_DATE, TO_DATE(to_date('20260331','YYYYMMDD'))) LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = DIM_INSTRUMENT_CONTRACT.V_CCY_CODE LEFT OUTER JOIN SEC_POOL_MASTER ON SEC_POOL_MASTER.V_SEC_POOL_ID = DIM_INSTRUMENT_CONTRACT.V_SEC_POOL_TYPE_CODE LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = FCT_ENTITY_INFO.N_GAAP_SKEY LEFT OUTER JOIN STG_MKT_INSTRUMENT_CONTRACT ON STG_MKT_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE AND STG_MKT_INSTRUMENT_CONTRACT.FIC_MIS_DATE = TO_DATE(to_date('20260331','YYYYMMDD')) LEFT JOIN DIM_COUNTRY ON DIM_COUNTRY.V_COUNTRY_ID=DIM_INSTRUMENT_CONTRACT.V_COUNTRY_CODE WHERE 1=1 AND 1=1 AND STG_BANK_POSITIONS.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE AND COALESCE(FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND, 'Y') = 'Y' AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FCT_ENTITY_INFO.N_RUN_SKEY = '870' AND DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE IN ('FLCS', 'PRCS')  /* AND DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE <> 'XSSPOTSPT'  */ AND TO_DATE(to_date('20260331','YYYYMMDD')) BETWEEN COALESCE(DIM_ORG_STRUCTURE.D_RECORD_START_DATE,TO_DATE(to_date('20260331','YYYYMMDD'))) AND COALESCE(DIM_ORG_STRUCTURE.D_RECORD_END_DATE, TO_DATE(to_date('20260331','YYYYMMDD'))) AND TO_DATE(to_date('20260331','YYYYMMDD')) BETWEEN COALESCE(DIM_BANK_POSITION.D_RECORD_START_DATE,TO_DATE(to_date('20260331','YYYYMMDD'))) AND  COALESCE(DIM_BANK_POSITION.D_RECORD_END_DATE, TO_DATE(to_date('20260331','YYYYMMDD'))) AND COALESCE(DIM_INSTRUMENT_CONTRACT.F_CAPITAL_CHARGE_EXCLUSION,'N') <> 'Y' AND TO_DATE(to_date('20260331','YYYYMMDD')) BETWEEN COALESCE(DIM_INSTRUMENT_CONTRACT.